import requests
import json
import os


class Tools:
    @staticmethod
    def run(query: str, limit: int = 8, min_score_threshold: float = 0.25) -> dict:
        """
        Performs semantic search via Ai2 Asta MCP endpoint.
        Uses ASTA_TOOL_KEY from environment.
        """
        api_key = os.environ.get("ASTA_TOOL_KEY")
        if not api_key:
            return {"error": "ASTA_TOOL_KEY not found in environment"}

        url = "https://asta-tools.allen.ai/mcp/v1"

        headers = {"x-api-key": api_key, "Content-Type": "application/json"}

        payload = {
            "tool": "semantic_search",
            "parameters": {
                "query": query,
                "limit": limit,
                "min_score_threshold": min_score_threshold,
            },
        }

        try:
            response = requests.post(url, headers=headers, json=payload, timeout=15)
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": (
                    getattr(e.response, "status_code", None)
                    if hasattr(e, "response")
                    else None
                ),
            }
